import React, { useEffect, useMemo, useState } from 'react';
import {
  Chart as ChartJS,
  ArcElement,
  BarElement,
  CategoryScale,
  LinearScale,
  Tooltip,
  Legend,
} from 'chart.js';
import { Doughnut, Bar } from 'react-chartjs-2';
import { emailService } from '../services/api';
import '../styles/ReportsAnalytics.css';

ChartJS.register(ArcElement, BarElement, CategoryScale, LinearScale, Tooltip, Legend);

const CURRENT_MODEL_HINTS = {
  url: ['random forest', 'random forest (original - 300 trees)'],
  content: ['logistic regression', 'logistic regression (saga)'],
};

const formatMetric = (value) => {
  if (value === null || value === undefined || Number.isNaN(Number(value))) {
    return '—';
  }
  return `${(Number(value) * 100).toFixed(2)}%`;
};

const formatSeconds = (value) => {
  if (value === null || value === undefined || Number.isNaN(Number(value))) {
    return '—';
  }
  return `${Number(value).toFixed(2)}s`;
};

const safeArray = (value) => (Array.isArray(value) ? value : []);

const normalizeModelMetrics = (list) =>
  safeArray(list)
    .filter((item) => item && item.status !== 'failed')
    .map((item) => ({
      model_name: item.model_name || 'Unknown Model',
      accuracy: Number(item.accuracy || 0),
      precision: Number(item.precision || 0),
      recall: Number(item.recall || 0),
      f1: Number(item.f1 || 0),
      roc_auc: Number(item.roc_auc || 0),
      training_time_seconds: Number(item.training_time_seconds || 0),
      status: item.status || 'success',
    }));

const matchesCurrentModel = (modelName, family) => {
  const normalized = String(modelName || '').toLowerCase();
  return (CURRENT_MODEL_HINTS[family] || []).some((hint) => normalized.includes(hint));
};

const findCurrentModelInComparison = (models, family) => {
  return models.find((model) => matchesCurrentModel(model.model_name, family)) || null;
};

const buildFallbackCurrentModel = (family, metrics) => {
  const names = {
    url: 'Random Forest',
    content: 'Logistic Regression',
  };

  return {
    model_name: names[family],
    accuracy: Number(metrics?.accuracy || 0),
    precision: Number(metrics?.precision || 0),
    recall: Number(metrics?.recall || 0),
    f1: Number(metrics?.f1 || 0),
    roc_auc: Number(metrics?.roc_auc || 0),
    training_time_seconds: Number(metrics?.training_time_seconds || 0),
    status: 'success',
    isFallback: true,
  };
};

const getBestAlternative = (models, currentModelName) => {
  const alternatives = safeArray(models).filter(
    (model) => model.model_name !== currentModelName
  );

  if (!alternatives.length) {
    return null;
  }

  return [...alternatives].sort((a, b) => b.f1 - a.f1)[0];
};

const ComparisonTable = ({ title, currentModel, models }) => {
  const bestAlternative = useMemo(
    () => getBestAlternative(models, currentModel?.model_name),
    [models, currentModel]
  );

  return (
    <div
      style={{
        marginTop: '1.5rem',
        border: '1px solid rgba(255,255,255,0.12)',
        borderRadius: '12px',
        padding: '1rem',
      }}
    >
      <h3 style={{ marginTop: 0 }}>{title}</h3>

      {currentModel && (
        <div
          style={{
            border: '1px solid rgba(255,255,255,0.10)',
            borderRadius: '10px',
            padding: '1rem',
            marginBottom: '1rem',
          }}
        >
          <h4 style={{ marginTop: 0 }}>Current production model</h4>
          <p style={{ marginTop: 0 }}>
            <strong>{currentModel.model_name}</strong>
          </p>

          <div
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(140px, 1fr))',
              gap: '0.75rem',
            }}
          >
            <div><strong>Accuracy</strong><br />{formatMetric(currentModel.accuracy)}</div>
            <div><strong>Precision</strong><br />{formatMetric(currentModel.precision)}</div>
            <div><strong>Recall</strong><br />{formatMetric(currentModel.recall)}</div>
            <div><strong>F1</strong><br />{formatMetric(currentModel.f1)}</div>
            <div><strong>ROC AUC</strong><br />{formatMetric(currentModel.roc_auc)}</div>
            <div><strong>Train Time</strong><br />{formatSeconds(currentModel.training_time_seconds)}</div>
          </div>
        </div>
      )}

      {bestAlternative && currentModel && (
        <div
          style={{
            border: '1px solid rgba(255,255,255,0.10)',
            borderRadius: '10px',
            padding: '1rem',
            marginBottom: '1rem',
          }}
        >
          <h4 style={{ marginTop: 0 }}>Best alternative not currently used</h4>
          <p style={{ marginTop: 0, marginBottom: '0.5rem' }}>
            <strong>{bestAlternative.model_name}</strong>
          </p>
          <p style={{ margin: 0 }}>
            F1: {formatMetric(bestAlternative.f1)} vs current {formatMetric(currentModel.f1)}
          </p>
          <p style={{ margin: '0.35rem 0 0 0' }}>
            Accuracy: {formatMetric(bestAlternative.accuracy)} vs current {formatMetric(currentModel.accuracy)}
          </p>
          <p style={{ margin: '0.35rem 0 0 0' }}>
            ROC AUC: {formatMetric(bestAlternative.roc_auc)} vs current {formatMetric(currentModel.roc_auc)}
          </p>
        </div>
      )}

      <div style={{ overflowX: 'auto' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr>
              <th style={{ textAlign: 'left', padding: '0.75rem' }}>Model</th>
              <th style={{ textAlign: 'left', padding: '0.75rem' }}>Used Now</th>
              <th style={{ textAlign: 'left', padding: '0.75rem' }}>Accuracy</th>
              <th style={{ textAlign: 'left', padding: '0.75rem' }}>Precision</th>
              <th style={{ textAlign: 'left', padding: '0.75rem' }}>Recall</th>
              <th style={{ textAlign: 'left', padding: '0.75rem' }}>F1</th>
              <th style={{ textAlign: 'left', padding: '0.75rem' }}>ROC AUC</th>
              <th style={{ textAlign: 'left', padding: '0.75rem' }}>Train Time</th>
            </tr>
          </thead>
          <tbody>
            {models.map((model) => {
              const isCurrent = currentModel?.model_name === model.model_name;

              return (
                <tr
                  key={`${title}-${model.model_name}`}
                  style={{
                    borderTop: '1px solid rgba(255,255,255,0.08)',
                    background: isCurrent ? 'rgba(37, 99, 235, 0.12)' : 'transparent',
                  }}
                >
                  <td style={{ padding: '0.75rem' }}>{model.model_name}</td>
                  <td style={{ padding: '0.75rem' }}>{isCurrent ? 'Yes' : 'No'}</td>
                  <td style={{ padding: '0.75rem' }}>{formatMetric(model.accuracy)}</td>
                  <td style={{ padding: '0.75rem' }}>{formatMetric(model.precision)}</td>
                  <td style={{ padding: '0.75rem' }}>{formatMetric(model.recall)}</td>
                  <td style={{ padding: '0.75rem' }}>{formatMetric(model.f1)}</td>
                  <td style={{ padding: '0.75rem' }}>{formatMetric(model.roc_auc)}</td>
                  <td style={{ padding: '0.75rem' }}>{formatSeconds(model.training_time_seconds)}</td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
};

const ReportsAnalytics = () => {
  const [reportData, setReportData] = useState(null);
  const [comparisonData, setComparisonData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const fetchReports = async () => {
    try {
      setLoading(true);

      const [statistics, phase2Metrics, phase2Comparison] = await Promise.all([
        emailService.getStatistics(),
        emailService.getPhase2Metrics(),
        emailService.getPhase2ModelComparison(),
      ]);

      setReportData({
        statistics,
        phase2Metrics,
      });

      setComparisonData(phase2Comparison);
      setError(null);
    } catch (err) {
      setError('Failed to load reports');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchReports();
  }, []);

  if (loading) {
    return <div className="reports-loading">Loading reports...</div>;
  }

  if (error) {
    return <div className="reports-error">{error}</div>;
  }

  const statistics = reportData?.statistics || {};
  const phase2Metrics = reportData?.phase2Metrics || {};

  const contentMetrics = phase2Metrics?.content_metrics || {};
  const urlMetrics = phase2Metrics?.url_metrics || {};

  const threatEntries = Object.entries(statistics.threat_distribution || {});
  const sourceCards = phase2Metrics?.data_sources || [];

  const urlComparisonModels = normalizeModelMetrics(
    comparisonData?.comparison?.report?.url_models?.metrics || []
  );

  const contentComparisonModels = normalizeModelMetrics(
    comparisonData?.comparison?.report?.content_models?.metrics || []
  );

  const currentUrlModel =
    findCurrentModelInComparison(urlComparisonModels, 'url') ||
    buildFallbackCurrentModel('url', urlMetrics);

  const currentContentModel =
    findCurrentModelInComparison(contentComparisonModels, 'content') ||
    buildFallbackCurrentModel('content', contentMetrics);

  const sortedUrlModels = [...urlComparisonModels].sort((a, b) => b.f1 - a.f1);
  const sortedContentModels = [...contentComparisonModels].sort((a, b) => b.f1 - a.f1);

  const modelChartData = {
    labels: ['Accuracy', 'Precision', 'Recall', 'F1', 'ROC AUC'],
    datasets: [
      {
        label: currentContentModel?.model_name || 'Content Model',
        data: [
          currentContentModel?.accuracy || 0,
          currentContentModel?.precision || 0,
          currentContentModel?.recall || 0,
          currentContentModel?.f1 || 0,
          currentContentModel?.roc_auc || 0,
        ],
        backgroundColor: 'rgba(37, 99, 235, 0.75)',
      },
      {
        label: currentUrlModel?.model_name || 'URL Model',
        data: [
          currentUrlModel?.accuracy || 0,
          currentUrlModel?.precision || 0,
          currentUrlModel?.recall || 0,
          currentUrlModel?.f1 || 0,
          currentUrlModel?.roc_auc || 0,
        ],
        backgroundColor: 'rgba(234, 88, 12, 0.75)',
      },
    ],
  };

  const threatChartData = {
    labels: threatEntries.length > 0 ? threatEntries.map(([label]) => label) : ['No threats'],
    datasets: [
      {
        data: threatEntries.length > 0 ? threatEntries.map(([, value]) => value) : [1],
        backgroundColor: ['#2563eb', '#dc2626', '#ea580c', '#16a34a', '#0f766e', '#7c3aed'],
        borderWidth: 0,
      },
    ],
  };

  return (
    <div className="reports-analytics-container">
      <div className="reports-header">
        <h1>Reports & Analytics</h1>
        <p>Operational view of detection trends, active Phase 2 models, and comparison against alternatives.</p>
      </div>

      <div
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))',
          gap: '1rem',
          marginBottom: '1.5rem',
        }}
      >
        <div className="report-card">
          <h3>Total Emails</h3>
          <p>{statistics.total_emails || 0}</p>
        </div>

        <div className="report-card">
          <h3>Phishing</h3>
          <p>{statistics.phishing_detected || 0}</p>
        </div>

        <div className="report-card">
          <h3>Average Risk</h3>
          <p>{(statistics.average_risk_score || 0).toFixed(3)}</p>
        </div>

        <div className="report-card">
          <h3>Detection Rate</h3>
          <p>{statistics.phishing_percentage || 0}%</p>
        </div>
      </div>

      <div
        style={{
          display: 'grid',
          gridTemplateColumns: 'minmax(320px, 1fr) minmax(320px, 1fr)',
          gap: '1.5rem',
        }}
      >
        <div
          style={{
            border: '1px solid rgba(255,255,255,0.12)',
            borderRadius: '12px',
            padding: '1rem',
          }}
        >
          <h2>Threat Distribution</h2>
          <Doughnut data={threatChartData} />
        </div>

        <div
          style={{
            border: '1px solid rgba(255,255,255,0.12)',
            borderRadius: '12px',
            padding: '1rem',
          }}
        >
          <h2>Active Model Quality</h2>
          <Bar data={modelChartData} />
        </div>
      </div>

      <div
        style={{
          marginTop: '1.5rem',
          border: '1px solid rgba(255,255,255,0.12)',
          borderRadius: '12px',
          padding: '1rem',
        }}
      >
        <h2>Phase 2 Metrics</h2>

        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))',
            gap: '1rem',
          }}
        >
          <div className="metric-card">
            <strong>Content model in use</strong>
            <div>{currentContentModel.model_name}</div>
          </div>

          <div className="metric-card">
            <strong>URL model in use</strong>
            <div>{currentUrlModel.model_name}</div>
          </div>

          <div className="metric-card">
            <strong>Content F1</strong>
            <div>{formatMetric(contentMetrics.f1 || 0)}</div>
          </div>

          <div className="metric-card">
            <strong>Content ROC AUC</strong>
            <div>{formatMetric(contentMetrics.roc_auc || 0)}</div>
          </div>

          <div className="metric-card">
            <strong>URL F1</strong>
            <div>{formatMetric(urlMetrics.f1 || 0)}</div>
          </div>

          <div className="metric-card">
            <strong>URL ROC AUC</strong>
            <div>{formatMetric(urlMetrics.roc_auc || 0)}</div>
          </div>

          <div className="metric-card">
            <strong>Trained At</strong>
            <div>
              {phase2Metrics.trained_at
                ? new Date(phase2Metrics.trained_at).toLocaleString()
                : 'Unknown'}
            </div>
          </div>
        </div>
      </div>

      <ComparisonTable
        title="URL model comparison"
        currentModel={currentUrlModel}
        models={sortedUrlModels.length ? sortedUrlModels : [currentUrlModel]}
      />

      <ComparisonTable
        title="Content model comparison"
        currentModel={currentContentModel}
        models={sortedContentModels.length ? sortedContentModels : [currentContentModel]}
      />

      <div
        style={{
          marginTop: '1.5rem',
          border: '1px solid rgba(255,255,255,0.12)',
          borderRadius: '12px',
          padding: '1rem',
        }}
      >
        <h2>Training Sources</h2>
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(260px, 1fr))',
            gap: '1rem',
          }}
        >
          {sourceCards.map((source) => (
            <div
              key={`${source.name}-${source.source}`}
              style={{
                border: '1px solid rgba(255,255,255,0.08)',
                borderRadius: '10px',
                padding: '1rem',
              }}
            >
              <h3 style={{ marginTop: 0 }}>{source.name}</h3>
              <p style={{ margin: '0.25rem 0' }}>{source.purpose}</p>
              <small>{source.source}</small>
            </div>
          ))}
        </div>
      </div>

      {comparisonData?.comparison?.available === false && (
        <div
          style={{
            marginTop: '1.5rem',
            border: '1px solid rgba(234, 179, 8, 0.35)',
            borderRadius: '12px',
            padding: '1rem',
          }}
        >
          <strong>Comparison report not found.</strong>
          <p style={{ marginBottom: 0 }}>
            Run <code>python backend/train_phase2_model_comparison.py</code> to generate
            <code> backend/artifacts/model_comparison/model_comparison_report.json</code>.
          </p>
        </div>
      )}
    </div>
  );
};

export default ReportsAnalytics;
